const body = $input.item.json.body;
const skill = body.skill;
const inputs = body.inputs || {};

const skills = {

  'north-star': {
    system: `You are an expert in product strategy and metrics. Help teams identify and validate their North Star metric — the single metric that best captures the value delivered to customers and predicts long-term business success. Use input/output metric thinking. Output in clean markdown.`,
    user: `Find and validate the North Star metric:

Product: ${inputs.product || ''}
Customer value delivered: ${inputs.customer_value || ''}
Business model: ${inputs.business_model || ''}
Current metrics tracked: ${inputs.current_metrics || ''}
Stage: ${inputs.stage || ''}

Output: North Star metric recommendation with rationale, 3-5 input metrics that drive it, metrics to avoid (vanity metrics), measurement plan, and how to use this in weekly team reviews.`
  },

  'metric-framework': {
    system: `You are an expert in product metrics and analytics. Build comprehensive metrics frameworks using AARRR (pirate metrics) or input/output methodology. Every metric should be measurable, actionable, and owned by someone. Output in clean markdown with structured tables.`,
    user: `Build a metrics framework:

Product: ${inputs.product || ''}
Business model: ${inputs.business_model || ''}
Stage: ${inputs.stage || ''}
Team structure: ${inputs.team_structure || ''}
Current data available: ${inputs.data_available || 'not specified'}
Framework preference: ${inputs.framework || 'AARRR'}

Output: complete metrics framework with metric name, definition, formula, target, measurement frequency, and owner for each layer, plus leading vs lagging indicator breakdown, and instrumentation checklist.`
  },

  'dashboard-design': {
    system: `You are an expert in data visualization and product analytics. Design metrics dashboards with the right metrics for the right audience. Different audiences need different views — executives, PMs, and engineers all need different dashboards. Output in clean markdown with layout descriptions.`,
    user: `Design a metrics dashboard:

Product: ${inputs.product || ''}
Primary audience: ${inputs.audience || ''}
Key decisions this dashboard should enable: ${inputs.decisions || ''}
Available data sources: ${inputs.data_sources || ''}
Update frequency: ${inputs.frequency || 'daily'}
Tool to be used: ${inputs.tool || 'not specified'}

Output: dashboard purpose statement, recommended metrics per section with definitions, layout design (described in text), alert thresholds to configure, and what to do when each metric moves in the wrong direction.`
  },

  'team-health': {
    system: `You are an expert in team dynamics and engineering effectiveness. Run structured team health checks that surface what's actually working and what isn't — not just what people are comfortable saying in public. Output in clean markdown with facilitation guide.`,
    user: `Run a team health check:

Team: ${inputs.team || ''}
Team size: ${inputs.size || ''}
Recent context: ${inputs.context || ''}
Areas of concern: ${inputs.concerns || 'none specified'}
Last health check: ${inputs.last_check || 'never'}

Output: health check survey questions (anonymous), facilitation guide for the team discussion, scoring rubric (traffic light per dimension), action planning template, and follow-up schedule.`
  },

  'meeting-notes': {
    system: `You are an expert at turning raw meeting notes into structured, actionable outputs. Extract decisions, action items, open questions, and key discussion points. Be ruthless about what matters vs what was just conversation. Output in clean markdown.`,
    user: `Process these meeting notes:

Meeting type: ${inputs.meeting_type || ''}
Attendees: ${inputs.attendees || ''}
Raw notes: ${inputs.notes || ''}
Date: ${inputs.date || new Date().toISOString().split('T')[0]}

Output: meeting summary (3 sentences max), decisions made (with rationale), action items (owner, task, due date), open questions (with suggested owner), and key context for anyone who missed it.`
  }

};

const skill_config = skills[skill];
if (!skill_config) {
  throw new Error(`Unknown skill: "${skill}". Valid options: ${Object.keys(skills).join(', ')}`);
}

return {
  skill: skill,
  system_prompt: skill_config.system,
  user_message: skill_config.user
};

const raw = $input.item.json;
const content = raw.content && raw.content[0] ? raw.content[0].text : '';
const skill = $('Build Prompt').item.json.skill;
return {
  skill: skill,
  content: content,
  word_count: content.split(/\s+/).filter(w => w).length,
  generated_at: new Date().toISOString()
};
